public static InstallationInfo Parse(JsonElement row)
    {
        string GetStringOr(string property, string fallback)
        {
            return row.TryGetProperty(property, out var el) && el.ValueKind == JsonValueKind.String
                ? el.GetString() ?? fallback
                : fallback;
        }

        string? GetOptionalString(string property)
        {
            return row.TryGetProperty(property, out var el) && el.ValueKind == JsonValueKind.String
                ? el.GetString()
                : null;
        }

        var pathStatus = GetOptionalString("pathStatus") is { Length: > 0 } parsedPathStatus
            ? parsedPathStatus
            : InstallationPathStatus.NotOnPath;

        return new InstallationInfo
        {
            Path = GetStringOr("path", string.Empty),
            CanonicalPath = GetOptionalString("canonicalPath"),
            Version = GetOptionalString("version"),
            Channel = GetOptionalString("channel"),
            Route = GetOptionalString("route"),
            PathStatus = pathStatus,
            Status = GetStringOr("status", InstallationInfoStatus.Ok),
            StatusReason = GetOptionalString("statusReason"),
        };
    }

private static string SanitizeStderr(string stderr)
    {
        // The byte cap is applied before sanitization so raw peer output is
        // always bounded; the truncation marker is appended after stripping.
        if (string.IsNullOrEmpty(stderr))
        {
            return string.Empty;
        }

        var builder = new StringBuilder(stderr.Length);
        for (var i = 0; i < stderr.Length; i++)
        {
            var ch = stderr[i];
            if (ch == '\u001b')
            {
                if (i + 1 < stderr.Length && stderr[i + 1] == '[')
                {
                    i += 2;
                    while (i < stderr.Length && (stderr[i] < '@' || stderr[i] > '~'))
                    {
                        i++;
                    }
                }
                continue;
            }

            if (char.IsControl(ch) && ch != '\n')
            {
                continue;
            }

            builder.Append(ch);
        }

        return builder.ToString().Trim();
    }

private static string? ValidateEmbeddedMetadata(EmbeddedAspireSkillsBundleMetadata metadata)
    {
        if (string.IsNullOrWhiteSpace(metadata.Version))
        {
            return AgentCommandStrings.AspireSkillsInstaller_MissingMetadataVersion;
        }

        if (!string.Equals(metadata.Repository, GitHubRepository, StringComparison.OrdinalIgnoreCase))
        {
            return string.Format(
                CultureInfo.CurrentCulture,
                AgentCommandStrings.AspireSkillsInstaller_MetadataRepositoryMismatch,
                metadata.Repository,
                GitHubRepository);
        }

        if (string.IsNullOrWhiteSpace(metadata.Tag))
        {
            return AgentCommandStrings.AspireSkillsInstaller_MissingMetadataTag;
        }

        if (string.IsNullOrWhiteSpace(metadata.AssetName))
        {
            return AgentCommandStrings.AspireSkillsInstaller_MissingMetadataAssetName;
        }

        if (string.IsNullOrWhiteSpace(metadata.Sha256))
        {
            return AgentCommandStrings.AspireSkillsInstaller_MissingMetadataSha256;
        }

        return null;
    }

private void CleanupStaleCacheEntries(string cacheRoot, string currentVersion)
    {
        if (!Directory.Exists(cacheRoot))
        {
            return;
        }

        var maxAge = ReadWindow(configuration, MaxCacheAgeKey, s_defaultMaxCacheAge);
        var now = DateTimeOffset.UtcNow;

        foreach (var directory in Directory.GetDirectories(cacheRoot))
        {
            try
            {
                var name = Path.GetFileName(directory);
                if (name.StartsWith(".", StringComparison.Ordinal) || string.Equals(name, currentVersion, StringComparison.Ordinal))
                {
                    continue;
                }

                var lastUsed = GetLastUsed(directory);
                if (now - lastUsed <= maxAge)
                {
                    continue;
                }

                TryDeleteDirectory(directory);
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                logger.LogDebug(ex, "Failed to evaluate Aspire skills cache directory {Directory} for cleanup.", directory);
            }
        }
    }

private static void ExtractZipArchive(string archivePath, string destinationDirectory)
    {
        var destinationRoot = Path.GetFullPath(destinationDirectory);
        Directory.CreateDirectory(destinationRoot);

        using var archive = ZipFile.OpenRead(archivePath);
        foreach (var entry in archive.Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.FullName))
            {
                continue;
            }

            var destinationPath = GetSafeArchiveDestinationPath(destinationRoot, entry.FullName);
            if (entry.FullName.EndsWith("/", StringComparison.Ordinal) || entry.FullName.EndsWith("\\", StringComparison.Ordinal))
            {
                Directory.CreateDirectory(destinationPath);
                continue;
            }

            var destinationFileDirectory = Path.GetDirectoryName(destinationPath);
            if (!string.IsNullOrEmpty(destinationFileDirectory))
            {
                Directory.CreateDirectory(destinationFileDirectory);
            }

            entry.ExtractToFile(destinationPath, overwrite: false);
        }
    }

private static DirectoryInfo FindBundleRoot(string extractionDirectory)
    {
        var rootManifestPath = Path.Combine(extractionDirectory, "skill-manifest.json");
        if (File.Exists(rootManifestPath))
        {
            return new DirectoryInfo(extractionDirectory);
        }

        var packageDirectory = Path.Combine(extractionDirectory, "package");
        var packageManifestPath = Path.Combine(packageDirectory, "skill-manifest.json");
        if (File.Exists(packageManifestPath))
        {
            return new DirectoryInfo(packageDirectory);
        }

        var topLevelBundleDirectories = Directory
            .EnumerateDirectories(extractionDirectory)
            .Where(directory => File.Exists(Path.Combine(directory, "skill-manifest.json")))
            .ToArray();

        if (topLevelBundleDirectories.Length == 1)
        {
            return new DirectoryInfo(topLevelBundleDirectories[0]);
        }

        if (topLevelBundleDirectories.Length > 1)
        {
            throw new InvalidOperationException("Downloaded Aspire skills package contains multiple skill-manifest.json files.");
        }

        throw new InvalidOperationException("Downloaded Aspire skills package does not contain skill-manifest.json.");
    }

internal static bool TryParseVersionOutput(string output, out SemVersion? version)
    {
        version = null;
        var versionString = output.Trim();

        if (string.IsNullOrEmpty(versionString))
        {
            return false;
        }

        // Version output may be on the first line if multi-line
        var lines = versionString.Split(['\n', '\r'], StringSplitOptions.RemoveEmptyEntries);
        if (lines.Length > 0)
        {
            versionString = lines[0].Trim();
        }

        // Try to extract the version from known formats like "GitHub Copilot CLI 0.0.397"
        var lastSpaceIndex = versionString.LastIndexOf(' ');
        if (lastSpaceIndex >= 0)
        {
            versionString = versionString[(lastSpaceIndex + 1)..];
        }

        // Trim common trailing punctuation that may follow the version (for example, "0.0.397.")
        versionString = versionString.TrimEnd('.', ',', ')');

        // Try to parse the version string (may have a 'v' prefix like "v1.2.3")
        if (versionString.StartsWith('v') || versionString.StartsWith('V'))
        {
            versionString = versionString[1..];
        }

        return SemVersion.TryParse(versionString, SemVersionStyles.Any, out version);
    }

public static bool HasServerConfigured(string configFilePath, string serverContainerKey, string serverName, Func<string, string>? preprocessContent = null)
    {
        if (!File.Exists(configFilePath))
        {
            return false;
        }

        try
        {
            var content = File.ReadAllText(configFilePath);

            if (preprocessContent is not null)
            {
                content = preprocessContent(content);
            }

            var config = JsonNode.Parse(content)?.AsObject();

            if (config is null)
            {
                return false;
            }

            if (config.TryGetPropertyValue(serverContainerKey, out var serversNode) && serversNode is JsonObject servers)
            {
                return servers.ContainsKey(serverName);
            }

            return false;
        }
        catch (JsonException)
        {
            return false;
        }
    }

private static async Task ApplyMcpConfigurationAsync(
    DirectoryInfo configDirectory,
    CancellationToken cancellationToken)
{
    var configFilePath = Path.Combine(configDirectory.FullName, OpenCodeConfigFileName);
    var config = await McpConfigFileHelper.ReadConfigAsync(configFilePath, cancellationToken, RemoveJsonComments);

    // Ensure schema is set for new configs
    if (!config.ContainsKey("$schema"))
    {
        config["$schema"] = "https://opencode.ai/config.json";
    }

    // Ensure "mcp" object exists
    if (!config.ContainsKey("mcp") || config["mcp"] is not JsonObject)
    {
        config["mcp"] = new JsonObject();
    }

    var mcp = config["mcp"]!.AsObject();

    // Add the "aspire" server configuration
    mcp[AspireServerName] = new JsonObject
    {
        ["type"] = "local",
        ["command"] = new JsonArray("aspire", "agent", "mcp"),
        ["enabled"] = true
    };

    // Write the updated config using AOT-compatible serialization
    var jsonOutput = JsonSerializer.Serialize(config, JsonSourceGenerationContext.Default.JsonObject);
    await File.WriteAllTextAsync(configFilePath, jsonOutput, cancellationToken);
}

private static async Task ApplyAspireMcpConfigurationAsync(
    DirectoryInfo vsCodeFolder,
    CancellationToken cancellationToken)
{
    // Ensure the .vscode folder exists
    if (!vsCodeFolder.Exists)
    {
        vsCodeFolder.Create();
    }

    var mcpConfigPath = Path.Combine(vsCodeFolder.FullName, McpConfigFileName);
    var config = await McpConfigFileHelper.ReadConfigAsync(mcpConfigPath, cancellationToken);

    // Ensure "servers" object exists
    if (!config.ContainsKey("servers") || config["servers"] is not JsonObject)
    {
        config["servers"] = new JsonObject();
    }

    var servers = config["servers"]!.AsObject();

    // Add or update the "aspire" server configuration
    servers[AspireServerName] = new JsonObject
    {
        ["type"] = "stdio",
        ["command"] = "aspire",
        ["args"] = new JsonArray("agent", "mcp")
    };

    // Write the updated config with indentation using AOT-compatible serialization
    var jsonContent = JsonSerializer.Serialize(config, JsonSourceGenerationContext.Default.JsonObject);
    await File.WriteAllTextAsync(mcpConfigPath, jsonContent, cancellationToken);
}

private static async Task<string[]?> FetchCapabilitiesAsync(JsonRpc rpc, ILogger logger, ProfilingTelemetry? profilingTelemetry, CancellationToken cancellationToken)
    {
        ArgumentNullException.ThrowIfNull(logger);

        try
        {
            var response = await rpc.InvokeWithProfilingAsync<GetCapabilitiesResponse?>(
                profilingTelemetry,
                "auxiliary",
                "GetCapabilitiesAsync",
                [new GetCapabilitiesRequest()],
                cancellationToken).ConfigureAwait(false);
            var capabilities = response?.Capabilities;
            logger.LogDebug("AppHost capabilities: {Capabilities}", capabilities is not null ? string.Join(", ", capabilities) : "null");
            return capabilities;
        }
        catch (RemoteMethodNotFoundException)
        {
            // Older AppHost without GetCapabilitiesAsync - assume v1 only
            logger.LogDebug("AppHost does not support GetCapabilitiesAsync, assuming v1 only");
            return null;
        }
        catch (Exception ex)
        {
            // Log any other exception
            logger.LogWarning(ex, "Failed to fetch capabilities from AppHost");
            return null;
        }
    }

public async Task<GetAppHostInfoResponse?> GetAppHostInfoV2Async(CancellationToken cancellationToken = default)
    {
        if (!SupportsV2)
        {
            // Fall back to v1 and convert
            var legacyInfo = await GetAppHostInformationAsync(cancellationToken).ConfigureAwait(false);
            if (legacyInfo is null)
            {
                return null;
            }

            return new GetAppHostInfoResponse
            {
                Pid = legacyInfo.ProcessId.ToString(System.Globalization.CultureInfo.InvariantCulture),
                AspireHostVersion = "unknown",
                AppHostPath = legacyInfo.AppHostPath,
                CliProcessId = legacyInfo.CliProcessId,
                StartedAt = legacyInfo.StartedAt,
                CliLogFilePath = legacyInfo.CliLogFilePath
            };
        }

        var rpc = EnsureConnected();

        _logger.LogDebug("Getting AppHost info (v2)");

        return await rpc.InvokeWithProfilingAsync<GetAppHostInfoResponse>(
            _profilingTelemetry,
            "auxiliary",
            "GetAppHostInfoAsync",
            [new GetAppHostInfoRequest()],
            cancellationToken).ConfigureAwait(false);
    }

public async Task<GetResourcesResponse> GetResourcesV2Async(GetResourcesRequest? request = null, CancellationToken cancellationToken = default)
    {
        request = AddClientCapabilities(request);

        if (!SupportsV2)
        {
            // Fall back to v1
            var snapshots = await GetResourceSnapshotsAsync(includeHidden: true, cancellationToken).ConfigureAwait(false);

            // Apply filter if specified
            if (!string.IsNullOrEmpty(request?.Filter))
            {
                var filter = request.Filter;
                snapshots = snapshots.Where(s => s.Name.Contains(filter, StringComparison.OrdinalIgnoreCase)).ToList();
            }

            return new GetResourcesResponse
            {
                Resources = snapshots.ToArray()
            };
        }

        var rpc = EnsureConnected();

        _logger.LogDebug("Getting resources (v2)");

        return await rpc.InvokeWithProfilingAsync<GetResourcesResponse>(
            _profilingTelemetry,
            "auxiliary",
            "GetResourcesAsync",
            [request],
            cancellationToken).ConfigureAwait(false) ?? new GetResourcesResponse { Resources = [] };
    }

public async Task<bool> StopAppHostV2Async(StopAppHostRequest? request = null, CancellationToken cancellationToken = default)
    {
        if (!SupportsV2)
        {
            // Fall back to v1
            return await StopAppHostAsync(cancellationToken).ConfigureAwait(false);
        }

        var rpc = EnsureConnected();

        _logger.LogDebug("Stopping AppHost (v2)");

        try
        {
            await rpc.InvokeWithProfilingAsync<StopAppHostResponse>(
                _profilingTelemetry,
                "auxiliary",
                "StopAsync",
                [request ?? new StopAppHostRequest()],
                cancellationToken).ConfigureAwait(false);
            return true;
        }
        catch (RemoteMethodNotFoundException)
        {
            // Fall back to v1
            return await StopAppHostAsync(cancellationToken).ConfigureAwait(false);
        }
    }

private void OnDisconnected(object? sender, JsonRpcDisconnectedEventArgs args)
    {
        // Prevent concurrent reconnection attempts
        lock (_lock)
        {
            if (_isReconnecting)
            {
                logger.LogDebug("Backchannel disconnected but reconnection already in progress, ignoring.");
                return;
            }
            _isReconnecting = true;
        }

        logger.LogInformation("Backchannel disconnected: {Reason}. Attempting to reconnect...", args.Reason);
        _ = Task.Run(async () =>
        {
            try
            {
                await ReconnectInternalAsync().ConfigureAwait(false);
            }
            catch (Exception ex)
            {
                logger.LogWarning(ex, "Failed to reconnect backchannel");
            }
            finally
            {
                lock (_lock)
                {
                    _isReconnecting = false;
                }
            }
        });
    }

