public static async Task<IAsyncEnumerable<T>> InvokeStreamingWithProfilingAsync<T>(
    this JsonRpc rpc,
    ProfilingTelemetry? profilingTelemetry,
    string connectionName,
    string methodName,
    object?[] arguments,
    CancellationToken cancellationToken,
    StreamingSpanLifetime spanLifetime = StreamingSpanLifetime.Enumeration)
{
    // Do not use `using` here: for a non-null response, activity ownership
    // transfers to the returned enumerable. If a caller obtains the enumerable
    // but never enumerates it, EnumerateWithProfiling will not dispose the activity.
    var activity = profilingTelemetry?.StartJsonRpcClientCall(connectionName, methodName, streaming: true) ?? default;
    arguments = WithTraceContext(arguments, activity.CreateBackchannelTraceContext());

    try
    {
        var response = await rpc.InvokeWithCancellationAsync<IAsyncEnumerable<T>>(methodName, arguments, cancellationToken).ConfigureAwait(false);
        activity.AddJsonRpcResponseReceivedEvent();

        return EnumerateWithProfiling(response, activity, spanLifetime, cancellationToken);
    }
    catch (Exception ex)
    {
        activity.SetError(ex);
        activity.Dispose();
        throw;
    }
}

internal static bool IsVersionedLayoutValid(string versionDir)
    {
        if (!Directory.Exists(versionDir))
        {
            return false;
        }

        var managedDir = Path.Combine(versionDir, BundleDiscovery.ManagedDirectoryName);
        var managedExe = Path.Combine(managedDir, BundleDiscovery.GetExecutableFileName(BundleDiscovery.ManagedExecutableName));

        if (!Directory.Exists(managedDir) || !File.Exists(managedExe))
        {
            return false;
        }

        try
        {
            var info = new FileInfo(managedExe);
            if (info.Length == 0)
            {
                return false;
            }
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            return false;
        }

        var dcpDir = Path.Combine(versionDir, BundleDiscovery.DcpDirectoryName);
        if (!Directory.Exists(dcpDir))
        {
            return false;
        }

        return true;
    }

private void RemoveAdminTrustRule(X509Certificate2 certificate)
    {
        Log.MacOSRemoveCertificateTrustRuleStart(GetDescription(certificate));
        var certificatePath = Path.GetTempFileName();
        try
        {
            var certBytes = certificate.Export(X509ContentType.Cert);
            File.WriteAllBytes(certificatePath, certBytes);
            var processInfo = new ProcessStartInfo(
                MacOSUntrustLegacyCertificateCommandLine,
                string.Format(
                    CultureInfo.InvariantCulture,
                    MacOSUntrustLegacyCertificateCommandLineArguments,
                    certificatePath
                ));

            using var process = Process.Start(processInfo);
            process!.WaitForExit();

            if (process.ExitCode != 0)
            {
                Log.MacOSRemoveCertificateTrustRuleError(process.ExitCode);
            }

            Log.MacOSRemoveCertificateTrustRuleEnd();
        }
        finally
        {
            try
            {
                File.Delete(certificatePath);
            }
            catch
            {
                // We don't care if we can't delete the temp file.
            }
        }
    }

private void RemoveCertificateFromKeychain(string keychain, X509Certificate2 certificate)
    {
        var processInfo = new ProcessStartInfo(
            MacOSDeleteCertificateCommandLine,
            string.Format(
                CultureInfo.InvariantCulture,
                MacOSDeleteCertificateCommandLineArgumentsFormat,
                certificate.Thumbprint.ToUpperInvariant(),
                keychain
            ))
        {
            RedirectStandardOutput = true,
            RedirectStandardError = true
        };

        if (Log.IsEnabled())
        {
            Log.MacOSRemoveCertificateFromKeyChainStart(keychain, GetDescription(certificate));
        }

        using (var process = Process.Start(processInfo))
        {
            var output = process!.StandardOutput.ReadToEnd() + process.StandardError.ReadToEnd();
            process.WaitForExit();

            if (process.ExitCode != 0)
            {
                Log.MacOSRemoveCertificateFromKeyChainError(process.ExitCode);
                throw new InvalidOperationException($@"There was an error removing the certificate with thumbprint '{certificate.Thumbprint}'.

{output}");
            }
        }

        Log.MacOSRemoveCertificateFromKeyChainEnd();
    }

private bool TryGetOpenSslDirectory([NotNullWhen(true)] out string? openSslDir)
    {
        openSslDir = null;

        try
        {
            var processInfo = new ProcessStartInfo(OpenSslCommand, $"version -d")
            {
                RedirectStandardOutput = true,
                RedirectStandardError = true
            };

            using var process = Process.Start(processInfo);
            var stdout = process!.StandardOutput.ReadToEnd();

            process.WaitForExit();
            if (process.ExitCode != 0)
            {
                Log.UnixOpenSslVersionFailed();
                return false;
            }

            var match = OpenSslVersionRegex.Match(stdout);
            if (!match.Success)
            {
                Log.UnixOpenSslVersionParsingFailed();
                return false;
            }

            openSslDir = match.Groups[1].Value;
            return true;
        }
        catch (Exception ex)
        {
            Log.UnixOpenSslVersionException(ex.Message);
            return false;
        }
    }

private bool TryGetOpenSslHash(string certificatePath, [NotNullWhen(true)] out string? hash)
    {
        hash = null;

        try
        {
            // c_rehash actually does this twice: once with -subject_hash (equivalent to -hash) and again
            // with -subject_hash_old.  Old hashes are only  needed for pre-1.0.0, so we skip that.
            var processInfo = new ProcessStartInfo(OpenSslCommand, $"x509 -hash -noout -in {certificatePath}")
            {
                RedirectStandardOutput = true,
                RedirectStandardError = true
            };

            using var process = Process.Start(processInfo);
            var stdout = process!.StandardOutput.ReadToEnd();

            process.WaitForExit();
            if (process.ExitCode != 0)
            {
                Log.UnixOpenSslHashFailed(certificatePath);
                return false;
            }

            hash = stdout.Trim();
            return true;
        }
        catch (Exception ex)
        {
            Log.UnixOpenSslHashException(certificatePath, ex.Message);
            return false;
        }
    }

internal static bool TryGetOpenSslDirectory([NotNullWhen(true)] out string? openSslDir)
    {
        openSslDir = null;

        try
        {
            var processInfo = new ProcessStartInfo("openssl", "version -d")
            {
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                UseShellExecute = false,
                CreateNoWindow = true
            };

            using var process = Process.Start(processInfo);
            if (process is null)
            {
                return false;
            }

            var stdout = process.StandardOutput.ReadToEnd();
            if (!process.WaitForExit(TimeSpan.FromSeconds(5)))
            {
                return false;
            }

            if (process.ExitCode != 0)
            {
                return false;
            }

            var match = OpenSslVersionRegex().Match(stdout);
            if (!match.Success)
            {
                return false;
            }

            openSslDir = match.Groups[1].Value;
            return true;
        }
        catch
        {
            // openssl may not be installed — silently fail
            return false;
        }
    }

internal async Task<AgentInitExecutionResult> PromptAndChainAsync(
    IInteractionService interactionService,
    int previousResultExitCode,
    DirectoryInfo workspaceRoot,
    PromptBinding<bool> agentInitBinding,
    CancellationToken cancellationToken,
    Func<SkillDefinition, bool>? selectByDefault = null)
{
    if (previousResultExitCode != CliExitCodes.Success)
    {
        return new(previousResultExitCode, [], []);
    }

    // Add a separating line between prompt and previous work in aspire new and aspire init.
    interactionService.DisplayEmptyLine();

    var runAgentInit = await interactionService.PromptConfirmAsync(
        SharedCommandStrings.PromptRunAgentInit,
        binding: agentInitBinding,
        cancellationToken: cancellationToken);

    if (runAgentInit)
    {
        return await ExecuteAgentInitAsync(workspaceRoot, parseResult: null, selectByDefault, cancellationToken);
    }

    return new(CliExitCodes.Success, [], []);
}

private static bool ShouldSkipBundleCatalogResolution(ParseResult? parseResult)
    {
        if (parseResult is null)
        {
            return false;
        }

        var optionResult = parseResult.GetResult(s_skillsOption);
        if (optionResult is null || optionResult.Implicit)
        {
            return false;
        }

        var value = parseResult.GetValue(s_skillsOption);
        if (string.Equals(value, ConsoleInteractionService.NoneChoice, StringComparison.OrdinalIgnoreCase))
        {
            return true;
        }

        if (string.IsNullOrWhiteSpace(value) ||
            string.Equals(value, ConsoleInteractionService.AllChoice, StringComparison.OrdinalIgnoreCase))
        {
            return false;
        }

        var selectedSkillNames = value.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
        return selectedSkillNames.Length > 0 &&
               selectedSkillNames.All(static name => IsCliDefinedSkillName(name));
    }

private void DisplayChildLogTail(string childLogFile, int childProcessId)
    {
        IReadOnlyList<CliLogFormat.FileLogEntry> replayEntries;
        IReadOnlyList<string> displayLines;
        try
        {
            replayEntries = ReadChildLogReplayTail(childLogFile, MaxParentLogReplayLines);
            displayLines = ReadChildLogTail(childLogFile, MaxDisplayedChildLogLines);
        }
        catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
        {
            logger.LogDebug(ex, "Failed to read child CLI log file {ChildLogFile}", childLogFile);
            return;
        }

        if (replayEntries.Count == 0 && displayLines.Count == 0)
        {
            return;
        }

        if (displayLines.Count > 0)
        {
            interactionService.DisplayMessage(KnownEmojis.Information, $"{RunCommandStrings.RecentAppHostStartupOutput}:");
            interactionService.DisplayLines(displayLines.Select(line => (OutputLineStream.StdOut, line)));
        }

        if (replayEntries.Count > 0)
        {
            ReplayChildLogTailToParentLog(childLogFile, childProcessId, replayEntries);
        }
    }

private static bool TryParseChildLogLineForReplay(string line, out CliLogFormat.FileLogEntry entry)
    {
        if (!CliLogFormat.TryParseFileLogLine(line, out entry))
        {
            return false;
        }

        if (string.IsNullOrWhiteSpace(entry.Message))
        {
            return false;
        }

        if (entry.Category is CliLogFormat.Categories.Stdout or CliLogFormat.Categories.Stderr)
        {
            return false;
        }

        if (entry.Category is CliLogFormat.Categories.Build or CliLogFormat.Categories.AppHost || entry.Category.StartsWith(CliLogFormat.Categories.AppHostPrefix, StringComparison.Ordinal))
        {
            return true;
        }

        if (entry.Category is CliLogFormat.Categories.GuestAppHostProject
            && entry.Message.StartsWith(CliLogFormat.MessagePrefixes.Executing, StringComparison.Ordinal))
        {
            return true;
        }

        if (entry.Level is CliLogFormat.FileLevelTokens.Warning or CliLogFormat.FileLevelTokens.Error or CliLogFormat.FileLevelTokens.Critical
            && entry.Category is not CliLogFormat.Categories.AspireCliTelemetry)
        {
            return true;
        }

        return false;
    }

private static bool TryFormatChildLogEntryForDisplay(CliLogFormat.FileLogEntry entry, out string displayLine)
    {
        displayLine = string.Empty;

        if (string.IsNullOrWhiteSpace(entry.Message))
        {
            return false;
        }

        if (entry.Category is CliLogFormat.Categories.Stdout or CliLogFormat.Categories.Stderr)
        {
            return false;
        }

        if (entry.Category is CliLogFormat.Categories.Build or CliLogFormat.Categories.AppHost || entry.Category.StartsWith(CliLogFormat.Categories.AppHostPrefix, StringComparison.Ordinal))
        {
            displayLine = entry.Message;
            return true;
        }

        if (entry.Category is CliLogFormat.Categories.GuestAppHostProject
            && entry.Message.StartsWith("AppHost server process has exited.", StringComparison.Ordinal))
        {
            return false;
        }

        if (entry.Level is CliLogFormat.FileLevelTokens.Warning or CliLogFormat.FileLevelTokens.Error or CliLogFormat.FileLevelTokens.Critical
            && entry.Category is not CliLogFormat.Categories.AspireCliTelemetry)
        {
            displayLine = $"{entry.Category}: {entry.Message}";
            return true;
        }

        return false;
    }

protected override async Task<CommandResult> ExecuteAsync(ParseResult parseResult, CancellationToken cancellationToken)
    {
        InteractionService.DisplayMessage(KnownEmojis.Information, CertificatesCommandStrings.TrustProgress);

        var result = await _certificateService.EnsureCertificatesTrustedAsync(cancellationToken);

        if (result.Success)
        {
            if (result.ResultCode == EnsureCertificateResult.PartiallyFailedToTrustTheCertificate)
            {
                InteractionService.DisplayMessage(KnownEmojis.Warning, CertificatesCommandStrings.TrustPartialSuccess);
            }
            else
            {
                InteractionService.DisplaySuccess(CertificatesCommandStrings.TrustSuccess);
            }

            return CommandResult.Success();
        }

        if (result.WasCancelled)
        {
            return CommandResult.Failure(CliExitCodes.FailedToTrustCertificates);
        }

        var details = string.Format(CultureInfo.CurrentCulture, CertificatesCommandStrings.TrustFailureDetailsFormat, result.ResultCode);
        return CommandResult.Failure(CliExitCodes.FailedToTrustCertificates, $"{CertificatesCommandStrings.TrustFailure} {details}");
    }
